/* eslint-disable no-alert */
import React, { useContext, useState } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  InputAdornment,
  IconButton,
  Paper,
  Link as MuiLink,
  Container,
  alpha,
  useTheme,
  Card,
  CardContent,
  Divider,
  Stack,
} from '@mui/material';
import { useForm } from 'react-hook-form';
import { Link, useHistory } from 'react-router-dom/cjs/react-router-dom.min';
import { PassportAuth } from '../../contexts/AuthContext';

// Icons
import VisibilityIcon from '@mui/icons-material/Visibility';
import VisibilityOffIcon from '@mui/icons-material/VisibilityOff';
import LockOutlinedIcon from '@mui/icons-material/LockOutlined';
import PersonOutlineOutlinedIcon from '@mui/icons-material/PersonOutlineOutlined';
import LoginIcon from '@mui/icons-material/Login';
import HowToRegOutlinedIcon from '@mui/icons-material/HowToRegOutlined';

export default function Login() {
  const {
    register,
    formState: { errors },
    handleSubmit,
  } = useForm();

  const { handleSignin } = useContext(PassportAuth);
  const history = useHistory();
  const theme = useTheme();
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const onSubmit = async (data, e) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      await handleSignin(data.username, data.password);
      history.push('/');
    } catch (error) {
      window.alert('ไม่สามารถเข้าสู่ระบบ กรุณาตรวจสอบชื่อผู้ใช้และรหัสผ่าน');
    } finally {
      setIsLoading(false);
    }
  };

  const handleTogglePassword = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        background: `linear-gradient(135deg, ${alpha(
          theme.palette.primary.main,
          0.8,
        )} 0%, ${alpha(theme.palette.primary.dark, 0.9)} 100%)`,
        py: 8,
      }}
    >
      <Container maxWidth="sm">
        <Card
          sx={{
            borderRadius: 2,
            boxShadow: '0 8px 24px rgba(0,0,0,0.12)',
            overflow: 'hidden',
          }}
        >
          <Box
            sx={{
              py: 4,
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              bgcolor: alpha(theme.palette.primary.main, 0.03),
              borderBottom: `1px solid ${alpha(theme.palette.divider, 0.1)}`,
            }}
          >
            <Typography variant="h5" fontWeight="bold" color="primary.dark">
              COREPLAN ERP
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
              Login to your account
            </Typography>
          </Box>

          <CardContent sx={{ p: 4 }}>
            <form onSubmit={handleSubmit(onSubmit)}>
              <Stack spacing={3}>
                <TextField
                  name="username"
                  label="username"
                  variant="outlined"
                  fullWidth
                  autoComplete="username"
                  autoFocus
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <PersonOutlineOutlinedIcon color="action" />
                      </InputAdornment>
                    ),
                  }}
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      borderRadius: 1.5,
                    },
                  }}
                  {...register('username', { required: true })}
                  error={!!errors.username}
                  helperText={errors.username && 'กรุณากรอกชื่อผู้ใช้'}
                />

                <TextField
                  label="password"
                  variant="outlined"
                  fullWidth
                  type={showPassword ? 'text' : 'password'}
                  autoComplete="current-password"
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <LockOutlinedIcon color="action" />
                      </InputAdornment>
                    ),
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton
                          onClick={handleTogglePassword}
                          edge="end"
                          size="small"
                          aria-label="toggle password visibility"
                        >
                          {showPassword ? (
                            <VisibilityOffIcon fontSize="small" />
                          ) : (
                            <VisibilityIcon fontSize="small" />
                          )}
                        </IconButton>
                      </InputAdornment>
                    ),
                  }}
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      borderRadius: 1.5,
                    },
                  }}
                  {...register('password', { required: true })}
                  error={!!errors.password}
                  helperText={errors.password && 'กรุณากรอกรหัสผ่าน'}
                />

                <Button
                  variant="contained"
                  fullWidth
                  type="submit"
                  disabled={isLoading}
                  startIcon={<LoginIcon />}
                  size="large"
                  sx={{
                    py: 1.2,
                    borderRadius: 1.5,
                    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                    textTransform: 'none',
                    fontSize: '1rem',
                  }}
                >
                  {isLoading ? 'Next...' : 'login'}
                </Button>
              </Stack>
            </form>

            <Box sx={{ mt: 3, textAlign: 'center' }}>
              <Divider sx={{ my: 2 }}>
                <Typography variant="body2" color="text.secondary">
                  or
                </Typography>
              </Divider>

              <Button
                component={Link}
                to="/auth/login/register"
                variant="outlined"
                color="primary"
                fullWidth
                startIcon={<HowToRegOutlinedIcon />}
                sx={{
                  borderRadius: 1.5,
                  py: 1,
                  textTransform: 'none',
                  mt: 1,
                }}
              >
                Register
              </Button>
            </Box>
          </CardContent>
        </Card>

        <Box sx={{ textAlign: 'center', mt: 3 }}>
          <Typography variant="body2" color="white" sx={{ opacity: 0.75 }}>
            © {new Date().getFullYear()} CodeProTeam.
          </Typography>
        </Box>
      </Container>
    </Box>
  );
}
